-- Shopping mall sample SQL
-- DBMS: MySQL / MariaDB
-- Tables: member_info, product_info, purchase_info, review_info, board_posts, delivery_info
-- Rows per table: 5000
-- Generated deterministically for lecture/testing.

use Chapter02Day02;
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

DROP VIEW IF EXISTS member_recommendation_signal_v;
DROP VIEW IF EXISTS customer_activity_timeline_v;
DROP VIEW IF EXISTS order_delivery_status_v;
DROP TABLE IF EXISTS delivery_info;
DROP TABLE IF EXISTS review_info;
DROP TABLE IF EXISTS board_posts;
DROP TABLE IF EXISTS purchase_info;
DROP TABLE IF EXISTS product_info;
DROP TABLE IF EXISTS member_info;

SET FOREIGN_KEY_CHECKS = 1;

CREATE TABLE member_info (
    member_id BIGINT PRIMARY KEY,
    email VARCHAR(120) NOT NULL UNIQUE,
    member_name VARCHAR(50) NOT NULL,
    phone VARCHAR(20) NOT NULL,
    address VARCHAR(200) NOT NULL,
    member_grade VARCHAR(20) NOT NULL,
    is_active CHAR(1) NOT NULL DEFAULT 'Y',
    created_at DATETIME NOT NULL,
    INDEX idx_member_name (member_name),
    INDEX idx_member_grade (member_grade),
    INDEX idx_member_created_at (created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE product_info (
    product_id BIGINT PRIMARY KEY,
    product_code VARCHAR(30) NOT NULL UNIQUE,
    category VARCHAR(50) NOT NULL,
    product_name VARCHAR(120) NOT NULL,
    price INT NOT NULL,
    stock_quantity INT NOT NULL,
    is_sale CHAR(1) NOT NULL DEFAULT 'Y',
    created_at DATETIME NOT NULL,
    INDEX idx_product_category (category),
    INDEX idx_product_price (price),
    INDEX idx_product_sale (is_sale)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE purchase_info (
    purchase_id BIGINT PRIMARY KEY,
    member_id BIGINT NOT NULL,
    product_id BIGINT NOT NULL,
    quantity INT NOT NULL,
    unit_price INT NOT NULL,
    discount_amount INT NOT NULL DEFAULT 0,
    total_amount INT NOT NULL,
    purchase_status VARCHAR(20) NOT NULL,
    payment_method VARCHAR(30) NOT NULL,
    purchased_at DATETIME NOT NULL,
    CONSTRAINT fk_purchase_member FOREIGN KEY (member_id) REFERENCES member_info(member_id),
    CONSTRAINT fk_purchase_product FOREIGN KEY (product_id) REFERENCES product_info(product_id),
    INDEX idx_purchase_member_date (member_id, purchased_at),
    INDEX idx_purchase_product_date (product_id, purchased_at),
    INDEX idx_purchase_status (purchase_status),
    INDEX idx_purchase_date (purchased_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE review_info (
    review_id BIGINT PRIMARY KEY,
    purchase_id BIGINT NOT NULL UNIQUE,
    member_id BIGINT NOT NULL,
    product_id BIGINT NOT NULL,
    rating TINYINT NOT NULL,
    review_content VARCHAR(500) NOT NULL,
    is_visible CHAR(1) NOT NULL DEFAULT 'Y',
    created_at DATETIME NOT NULL,
    CONSTRAINT fk_review_purchase FOREIGN KEY (purchase_id) REFERENCES purchase_info(purchase_id),
    CONSTRAINT fk_review_member FOREIGN KEY (member_id) REFERENCES member_info(member_id),
    CONSTRAINT fk_review_product FOREIGN KEY (product_id) REFERENCES product_info(product_id),
    INDEX idx_review_product_rating (product_id, rating),
    INDEX idx_review_member_date (member_id, created_at),
    INDEX idx_review_visible (is_visible)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE board_posts (
    post_id BIGINT PRIMARY KEY,
    member_id BIGINT NOT NULL,
    board_category VARCHAR(30) NOT NULL,
    title VARCHAR(200) NOT NULL,
    content VARCHAR(1000) NOT NULL,
    view_count INT NOT NULL DEFAULT 0,
    is_visible CHAR(1) NOT NULL DEFAULT 'Y',
    created_at DATETIME NOT NULL,
    updated_at DATETIME NOT NULL,
    CONSTRAINT fk_board_member FOREIGN KEY (member_id) REFERENCES member_info(member_id),
    INDEX idx_board_member_date (member_id, created_at),
    INDEX idx_board_category_date (board_category, created_at),
    INDEX idx_board_visible (is_visible)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

START TRANSACTION;



















































COMMIT;

-- Quick row-count check
SELECT 'member_info' AS table_name, COUNT(*) AS row_count FROM member_info
UNION ALL SELECT 'product_info', COUNT(*) FROM product_info
UNION ALL SELECT 'purchase_info', COUNT(*) FROM purchase_info
UNION ALL SELECT 'review_info', COUNT(*) FROM review_info
UNION ALL SELECT 'board_posts', COUNT(*) FROM board_posts;

-- Useful test queries
SELECT m.member_id, m.member_name, COUNT(p.purchase_id) AS purchase_count, SUM(p.total_amount) AS total_spent
FROM member_info m
JOIN purchase_info p ON p.member_id = m.member_id
GROUP BY m.member_id, m.member_name
ORDER BY total_spent DESC
LIMIT 10;

SELECT pr.product_id, pr.product_name, AVG(r.rating) AS avg_rating, COUNT(r.review_id) AS review_count
FROM product_info pr
JOIN review_info r ON r.product_id = pr.product_id
GROUP BY pr.product_id, pr.product_name
ORDER BY avg_rating DESC, review_count DESC
LIMIT 10;

-- Extended lecture data: delivery status and reusable query views
-- delivery_info is derived from purchase_info for JOIN/FULL JOIN/UNION practice.

DROP VIEW IF EXISTS member_recommendation_signal_v;
DROP VIEW IF EXISTS customer_activity_timeline_v;
DROP VIEW IF EXISTS order_delivery_status_v;
DROP TABLE IF EXISTS delivery_info;

CREATE TABLE delivery_info (
    delivery_id BIGINT PRIMARY KEY,
    purchase_id BIGINT NOT NULL UNIQUE,
    member_id BIGINT NOT NULL,
    delivery_status VARCHAR(20) NOT NULL,
    carrier VARCHAR(30) NOT NULL,
    tracking_no VARCHAR(40) NULL,
    shipped_at DATETIME NULL,
    delivered_at DATETIME NULL,
    last_updated_at DATETIME NOT NULL,
    CONSTRAINT fk_delivery_purchase FOREIGN KEY (purchase_id) REFERENCES purchase_info(purchase_id),
    CONSTRAINT fk_delivery_member FOREIGN KEY (member_id) REFERENCES member_info(member_id),
    INDEX idx_delivery_member_status (member_id, delivery_status),
    INDEX idx_delivery_status_updated (delivery_status, last_updated_at),
    INDEX idx_delivery_purchase (purchase_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

    delivery_id,
    purchase_id,
    member_id,
    delivery_status,
    carrier,
    tracking_no,
    shipped_at,
    delivered_at,
    last_updated_at
)
SELECT
    p.purchase_id AS delivery_id,
    p.purchase_id,
    p.member_id,
    CASE p.purchase_status
        WHEN 'PAID' THEN 'READY'
        WHEN 'SHIPPED' THEN 'IN_TRANSIT'
        WHEN 'DELIVERED' THEN 'DELIVERED'
        WHEN 'CANCELLED' THEN 'NO_DELIVERY'
        WHEN 'REFUNDED' THEN 'NO_DELIVERY'
        ELSE 'UNKNOWN'
    END AS delivery_status,
    CASE MOD(p.purchase_id, 4)
        WHEN 0 THEN 'CJ대한통운'
        WHEN 1 THEN '로젠택배'
        WHEN 2 THEN '한진택배'
        ELSE '우체국택배'
    END AS carrier,
    CASE
        WHEN p.purchase_status IN ('SHIPPED', 'DELIVERED')
        THEN CONCAT('TRK', LPAD(p.purchase_id, 10, '0'))
        ELSE NULL
    END AS tracking_no,
    CASE
        WHEN p.purchase_status IN ('SHIPPED', 'DELIVERED')
        THEN DATE_ADD(p.purchased_at, INTERVAL 1 DAY)
        ELSE NULL
    END AS shipped_at,
    CASE
        WHEN p.purchase_status = 'DELIVERED'
        THEN DATE_ADD(p.purchased_at, INTERVAL 3 DAY)
        ELSE NULL
    END AS delivered_at,
    CASE
        WHEN p.purchase_status = 'DELIVERED' THEN DATE_ADD(p.purchased_at, INTERVAL 3 DAY)
        WHEN p.purchase_status = 'SHIPPED' THEN DATE_ADD(p.purchased_at, INTERVAL 1 DAY)
        ELSE p.purchased_at
    END AS last_updated_at
FROM purchase_info p;

CREATE VIEW order_delivery_status_v AS
SELECT
    p.purchase_id,
    p.member_id,
    m.member_name,
    p.product_id,
    pr.product_name,
    p.purchase_status,
    d.delivery_status,
    d.carrier,
    d.tracking_no,
    p.total_amount,
    p.purchased_at,
    d.shipped_at,
    d.delivered_at
FROM purchase_info p
JOIN member_info m ON m.member_id = p.member_id
JOIN product_info pr ON pr.product_id = p.product_id
LEFT JOIN delivery_info d ON d.purchase_id = p.purchase_id;

CREATE VIEW customer_activity_timeline_v AS
SELECT member_id, purchased_at AS event_at, 'ORDER' AS event_type, CAST(purchase_id AS CHAR) AS ref_id
FROM purchase_info
UNION ALL
SELECT member_id, last_updated_at AS event_at, 'DELIVERY' AS event_type, CAST(delivery_id AS CHAR) AS ref_id
FROM delivery_info
UNION ALL
SELECT member_id, created_at AS event_at, CONCAT('BOARD_', board_category) AS event_type, CAST(post_id AS CHAR) AS ref_id
FROM board_posts
WHERE is_visible = 'Y';

CREATE VIEW member_recommendation_signal_v AS
SELECT p.member_id, p.product_id, pr.category, 5 AS score, 'PURCHASE_CATEGORY' AS signal_type
FROM purchase_info p
JOIN product_info pr ON pr.product_id = p.product_id
WHERE p.purchase_status IN ('PAID', 'SHIPPED', 'DELIVERED')
UNION ALL
SELECT r.member_id, r.product_id, pr.category, 3 AS score, 'HIGH_RATING_REVIEW' AS signal_type
FROM review_info r
JOIN product_info pr ON pr.product_id = r.product_id
WHERE r.rating >= 4 AND r.is_visible = 'Y'
UNION ALL
SELECT b.member_id, p.product_id, pr.category, 2 AS score, 'DELIVERY_QNA_CONTEXT' AS signal_type
FROM board_posts b
JOIN purchase_info p ON p.member_id = b.member_id
JOIN product_info pr ON pr.product_id = p.product_id
WHERE b.board_category = '배송' AND b.is_visible = 'Y'
UNION ALL
SELECT m.member_id, pr.product_id, pr.category, 4 AS score, 'VIP_POPULAR_CATEGORY' AS signal_type
FROM member_info m
JOIN product_info pr ON pr.is_sale = 'Y'
WHERE m.member_grade = 'VIP' AND MOD(pr.product_id, 50) = 0;

-- Extended row-count check
SELECT 'delivery_info' AS table_name, COUNT(*) AS row_count FROM delivery_info;

-- Example: recommendation score by member/category
SELECT member_id, category, SUM(score) AS recommend_score
FROM member_recommendation_signal_v
GROUP BY member_id, category
ORDER BY recommend_score DESC
LIMIT 20;
